var texto = $input.first().json.output;
var partes = texto.split("||");
var resultado = [];
for (var i = 0; i < partes.length; i++) {
  var msg = partes[i].trim();
  if (msg.length > 0) {
    resultado.push({ json: { output: msg } });
  }
}
return resultado;

